// utils/keys.ts
function setupKeyControls(config3, onConfigChange, onHotkeyLog) {
  const parameters = [
    {
      name: "minCellSize",
      display: "Grid Resolution (cellSize)",
      min: config3.minCellSize,
      max: config3.maxCellSize,
      getValue: (config4) => config4.minCellSize,
      setValue: (config4, value) => {
        config4.minCellSize = value;
      }
    },
    {
      name: "minTickRate",
      display: "Tick Rate",
      min: config3.minTickRate,
      max: config3.maxTickRate,
      getValue: (config4) => config4.minTickRate,
      setValue: (config4, value) => {
        config4.minTickRate = value;
      }
    },
    {
      name: "activeCellDensity",
      display: "Active Cell Density",
      min: 0.1,
      max: 1,
      getValue: (config4) => config4.activeCellDensity,
      setValue: (config4, value) => {
        config4.activeCellDensity = value;
      }
    }
  ];
  let activeParamIndex = 0;
  let currentMacro = null;
  onHotkeyLog(`Parameter: ${parameters[activeParamIndex].display}. Use Tab to cycle; ArrowUp/Down to adjust.`);
  window.addEventListener("keydown", (e) => {
    if (e.key === "Tab") {
      e.preventDefault();
      activeParamIndex = (activeParamIndex + 1) % parameters.length;
      currentMacro = null;
      onHotkeyLog(`Active param: ${parameters[activeParamIndex].display}`);
      return;
    }
    if (currentMacro) {
      if (e.key === "ArrowUp") {
        currentMacro.setBaseline(currentMacro.getBaseline() + 0.1);
      } else if (e.key === "ArrowDown") {
        currentMacro.setBaseline(currentMacro.getBaseline() - 0.1);
      }
      return;
    }
    if (e.key === "ArrowUp" || e.key === "ArrowDown") {
      const param = parameters[activeParamIndex];
      const currentValue = param.getValue(config3);
      const range = param.max - param.min;
      const step = range * 0.05;
      let newValue;
      if (e.key === "ArrowUp") {
        newValue = currentValue + step;
        if (newValue > param.max) newValue = param.max;
      } else {
        newValue = currentValue - step;
        if (newValue < param.min) newValue = param.min;
      }
      newValue = param.name === "minTickRate" || param.name === "minCellSize" ? Math.round(newValue) : Math.round(newValue * 100) / 100;
      onHotkeyLog(`${param.display} updated: ${currentValue} -> ${newValue}`);
      param.setValue(config3, newValue);
      onConfigChange();
    }
  });
  return {
    setCurrentMacro: (macro) => {
      currentMacro = macro;
      onHotkeyLog(`Macro control activated.`);
    },
    clearCurrentMacro: () => {
      currentMacro = null;
      onHotkeyLog(`Macro control cleared.`);
    }
  };
}

