var Macro = class {
  constructor() {
    __publicField(this, "targets", []);
    __publicField(this, "useCurrentBaseline", false);
    __publicField(this, "currentBaseline", 0.5);
    __publicField(this, "trigFunc", "sin");
    __publicField(this, "periodMultiplier", 1);
    __publicField(this, "lfoPeriod", 100);
    __publicField(this, "dampener", 0.5);
    __publicField(this, "enabled", true);
  }
  setBaseline(value) {
    this.currentBaseline = value;
  }
  getBaseline() {
    return this.currentBaseline;
  }
  getModulation(tick) {
    const adjustedTick = tick * this.periodMultiplier;
    const phase = adjustedTick % this.lfoPeriod / this.lfoPeriod;
    let wave;
    switch (this.trigFunc) {
      case "sin":
        wave = Math.sin(phase * 2 * Math.PI);
        break;
      case "cos":
        wave = Math.cos(phase * 2 * Math.PI);
        break;
      case "tan":
        wave = Math.tan(phase * 2 * Math.PI);
        break;
      case "csc":
        wave = 1 / Math.sin(phase * 2 * Math.PI);
        break;
      case "sec":
        wave = 1 / Math.cos(phase * 2 * Math.PI);
        break;
      case "cot":
        wave = 1 / Math.tan(phase * 2 * Math.PI);
        break;
      default:
        wave = Math.sin(phase * 2 * Math.PI);
    }
    return wave * this.dampener;
  }
};

